function infT = fTrexRoiInfV02(dat)%% create information text for plot%% infT = fTrexRoiInfV02(dat)%% dat: data% infT: information text%% Function TREX ROI inf, ver.2% Kei Nakamura% Created on Saturday, May 31st 2008.% Modified on Monday, November 8th 2010.%% main bodyinfT{1} = ['chrg[pC]:',num2str(0.001*floor(1000*dat(4)))];infT{2} = ['enrg[mJ]:',num2str(0.001*floor(1000*dat(5)))];infT{3} = ['peakE[MeV]:',num2str(floor(dat(16)))];infT{4} = ['meanE[MeV]:',num2str(floor(dat(9)))];infT{5} = ['fwhmDv[mrad]:',num2str(floor(dat(14)))];infT{6} = ['fwhmSpr[%]:',num2str(floor(dat(20)))];infT{7} = ['fwhmRsl[%]:',num2str(floor(dat(19)))];infT{8} = ['MinE[MeV]:',num2str(floor(dat(22)))];infT{9} = ['MaxE[MeV]:',num2str(floor(dat(21)))];
